"""
mkt-original — 2 Kings 12–14
run: python3 scripts/zc-original-2kings-12-14.py

Ch12: Joash repairs the temple; strips it to pay off Hazael; assassinated
Ch13: Jehoahaz implores YHWH; Elisha's death; bones miracle; Jehoash vs. Aram
Ch14: Amaziah's individual-guilt principle (Deut 24:16); Jeroboam II; Jonah named
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

KINGS2_ORIGINAL = {
  "12": {
    "1": "<p>Jehoash (<em>Yəhôʾāš</em>, YHWH-has-given) becomes king in Jehu's seventh year — the synchronism anchors him in the Jehu dynasty of Israel while his long forty-year reign in Jerusalem marks him as the most durable of the Athaliah-crisis survivors.</p>",
    "2": "<p><em>ʾăšer hôrāhû Yəhôyāḏāʿ hakkōhēn</em> — 'because Jehoiada the priest instructed him.' The syntax makes Joash's righteousness contingent (<em>kol-yəmê ʾăšer hôrāhû</em>, 'all his days, to the extent that Jehoiada instructed him'); where the mentorship ends, the good ends with it (cf. vv20-21 — apostasy and assassination after Jehoiada's death in 2 Chr 24:17-22).</p>",
    "3": "<p><em>habbāmôt lōʾ-sārû</em> — 'the high places were not removed.' The bāmôt qualification recurs in every otherwise-positive regnal evaluation in Kings; it marks the limit of the Josianic standard these pre-Josiah kings cannot reach and signals that the cult is still partially decentralized despite Jerusalem's central sanctuary.</p>",
    "4": "<p>Three categories of temple income: (1) <em>kesef ʿōbēr</em> — 'money from those who pass over,' the half-shekel census/poll tax of Exod 30:12-16; (2) <em>kesef nepeš ʿerěkô</em> — 'money of the soul of one's valuation,' the Levitical redemption assessments of Lev 27; (3) <em>kesef yāḇîʾ ʾîš ʿal libbô</em> — 'money any man brings on his heart,' i.e., freewill offerings. The classification shows Joash understood the three legally distinct funding streams and intended a systematic collection.</p>",
    "5": "<p><em>yəḥazzəqû ʾeṯ-beḏeq habbayiṯ</em> — 'let them repair the breaches of the house.' <em>beḏeq</em> (breach, crack) is the structural term for damage to load-bearing walls; the priests are to collect the money and disburse it to the craftsmen who repair the actual stone and timber.</p>",
    "6": "<p>By the twenty-third year of Joash the priests had still not repaired the temple breaches — the system of v5 failed, either from priestly diversion of funds or administrative neglect. The failure prompts Joash's reform of the collection system in vv9-16.</p>",
    "7": "<p>Joash summons Jehoiada and the priests and prohibits them from receiving money from their acquaintances (<em>mimmayyuddaʿăkhem</em>) and from the repair obligation. The king does not punish for past failure but restructures the system going forward — a pragmatic rather than punitive response.</p>",
    "8": "<p>The priests agree to neither receive money nor repair the temple — they yield the fiscal responsibility back to the crown. This transfer of temple finances from priestly to royal oversight is a significant administrative shift in the relationship between palace and sanctuary.</p>",
    "9": "<p>Jehoiada the priest bored a hole (<em>wayyiqboʿ ḥōr</em>) in the lid of the chest (<em>ʾārôn</em>) and set it beside the altar at the right of the entrance. The gatekeeping priests put all the money brought into YHWH's house into it — a transparent, auditable collection system replacing the priestly ad hoc arrangement.</p>",
    "10": "<p>When the chest was full, the king's secretary and the high priest would count the silver and wrap it in bags. The dual-oversight system (royal secretary + high priest) provides accountability — neither party handles money alone.</p>",
    "11": "<p>The weighed-out money was given directly to the overseers (<em>pəqûḏîm</em>, the appointed ones) of the work on YHWH's house, who disbursed to carpenters and builders, masons and stonecutters, timber-buyers and hewn-stone-buyers. The craftsmen received wages directly, bypassing priestly intermediaries.</p>",
    "12": "<p>All the skilled trades required for temple restoration are listed — carpenters, builders, masons, stonecutters — plus quarried stone (<em>ʾaḇnê māḥṣāḇ</em>) and timber for the structural repairs. The enumeration signals both the scope and the competence of the project.</p>",
    "13": "<p>A notable limitation: the silver was not used to make silver basins, snuffers, bowls, trumpets, or gold and silver vessels for YHWH's house. The repair project was strictly structural, not decorative — the priority was the building's fabric, not its furnishings.</p>",
    "14": "<p>The craftsmen used the money for repairs without any accounting to those who gave it, <em>kî beʾĕmûnāh hêm ʿōśîm</em> — 'because they worked in faithfulness/trustworthiness.' <em>ʾĕmûnāh</em> (faithfulness) is the noun from <em>ʾāman</em>, which underlies the liturgical <em>ʾāmēn</em>; the craftsmen's integrity made detailed auditing unnecessary.</p>",
    "15": "<p>The same note as v14 — no accounting required because of the workers' <em>ʾĕmûnāh</em>. The double mention underscores that trustworthy stewardship makes bureaucratic oversight secondary; the integrity of the workers validates the entire project.</p>",
    "16": "<p>Guilt offering (<em>ʾāšām</em>) and sin offering (<em>ḥaṭṭāʾṯ</em>) money went to the priests separately — it was not deposited in the chest. The text thus distinguishes the two funding streams: building funds go into the chest; sacrificial-system proceeds remain in priestly hands. The two budgets do not mingle.</p>",
    "17": "<p>Hazael attacks Gath and turns to attack Jerusalem. Joash takes the <em>qoḏāšîm</em> (consecrated/sacred things) dedicated by his ancestors Jehoshaphat, Joram, Ahaziah, and himself, plus all the gold in the temple treasury, and sends them to Hazael. The bitter irony: the king who repaired the temple's structure strips its consecrated wealth to buy off a foreign threat — the temple budget built up over three reigns is dispatched in one payment.</p>",
    "18": "<p><em>wayyēleḵ mēʿal Yərûšālem</em> — 'and he withdrew from Jerusalem.' The tribute payment works: Hazael turns away. But the cost was the sacred dedications, the gold reserves, and presumably the goodwill built by the temple repair project. The story implies that material security purchased at the cost of the sacred is not security at all.</p>",
    "19": "<p>The remaining acts of Joash are in the royal chronicle. His reign ends not with a full regnal account but with the assassination record that follows — the end is shaped by the murder, not by the building project.</p>",
    "20": "<p>Joash's servants conspire against him and strike him at <em>bêṯ millôʾ hayyôrēḏ Sillāʾ</em> — the house of Millo, which goes down to Silla. The location is unknown but it belongs to the Millo-complex, the fill-work of the older City of David. The assassination terminates a forty-year reign by a conspiracy among his own court.</p>",
    "21": "<p>The assassins are named: Jozachar son of Shimeath and Jehozabad son of Shomer. Both names and maternal pedigrees are given — the text does not conceal the perpetrators. Joash is buried with his fathers in the City of David; his son Amaziah succeeds him.</p>"
  },
  "13": {
    "1": "<p>Jehoahaz son of Jehu begins to reign over Israel in Samaria in the twenty-third year of Joash of Judah. The synchronism ties the two kingdoms together chronologically through the Jehu dynasty and the Joash interregnum.</p>",
    "2": "<p><em>wayyēleḵ bəḥaṭṭôʾṯ Yārābəʿām</em> — 'he walked in the sins of Jeroboam.' The fixed formulaic indictment of every northern king since 1 Kgs 12:30; its repetition signals that Jeroboam's golden calves function as a permanent structural sin of the northern kingdom, not merely individual apostasies.</p>",
    "3": "<p>YHWH's anger burns against Israel and he gives them into the hand of Hazael king of Aram and Ben-hadad son of Hazael — the two successive rulers of the Aramean empire who dominated Israel through most of Jehu's dynasty. The punishment is YHWH's direct action through foreign military pressure.</p>",
    "4": "<p><em>wayyəḥal Yəhôʾāḥāz ʾeṯ-pənê YHWH</em> — 'Jehoahaz implored/sought the face of YHWH.' <em>ḥālāh pānîm</em> (to make the face of YHWH) is an idiom for earnest petition; <em>ḥālāh</em> literally means to be weak or sick, idiomatically to approach in humility. YHWH listened because he saw the oppression of Israel by the king of Aram — divine mercy operates on compassion for human suffering, not exclusively on merit.</p>",
    "5": "<p><em>wayyitten YHWH lə yiśrāʾēl môšîaʿ</em> — 'YHWH gave Israel a deliverer/savior.' <em>môšîaʿ</em> is the participle of <em>yāšaʿ</em>, the same root as Yeshua; the historical deliverer here is likely an Assyrian king (Adad-nirari III pressed Aram) rather than an Israelite figure — YHWH's salvation instruments can be pagan powers. Israel dwelt in its tents as before, i.e., returned to normality; yet the sin of Jeroboam continued (v6).</p>",
    "6": "<p>Despite YHWH's deliverance, Israel did not depart from the house of Jeroboam. The <em>ʾăšērāh</em> (Asherah pole) still stood in Samaria — a visible symbol of syncretism at the capital. Deliverance from oppression did not produce repentance; the structural cult persisted.</p>",
    "7": "<p>Jehoahaz's remaining military force is reduced to fifty horsemen, ten chariots, ten thousand foot soldiers — <em>kî ʾibbaḏām melek ʾărām wayyəśimēm kəʿāpār lāḏuš</em>, 'because the king of Aram destroyed them and made them like dust for threshing.' The image of threshed dust conveys near-total pulverization; Israel's military capacity is barely functional.</p>",
    "8": "<p>The rest of Jehoahaz's acts — 'his might' (<em>gəḇûrāṯô</em>) and all he did — are in the Book of the Chronicles of the Kings of Israel. The standard archival reference; the irony is that the chapter documenting his military humiliation must appeal to a record that uses the term 'might.'</p>",
    "9": "<p>Jehoahaz dies and is buried in Samaria; his son Joash (Jehoash) reigns in his place. The brief dynastic succession notice moves quickly to the more theologically significant reign of Jehoash, who will have the encounter with the dying Elisha.</p>",
    "10": "<p>Jehoash son of Jehoahaz begins to reign over Israel in Samaria in the thirty-seventh year of Joash of Judah, reigning sixteen years. The synchronism with Joash of Judah (a different Joash) produces a confusing name-overlap that the narrative handles by keeping strict synchronistic tracking.</p>",
    "11": "<p><em>wayyaʿaś hārāʿ bəʿênê YHWH lōʾ-sār mikkol-ḥaṭṭôʾṯ Yārābəʿām</em> — the standard negative formula; Jehoash of Israel follows Jeroboam's sins despite being the king who will be instructed by the dying Elisha and who will achieve military victories against Aram.</p>",
    "12": "<p>The rest of Jehoash's acts include his 'might' and his war with Amaziah of Judah — a proleptic reference to the conflict described in ch14. The archival notice also appears in full in 14:15, suggesting the compiler has integrated the Elisha deathbed episode between the two archival references to Jehoash.</p>",
    "13": "<p>Jehoash dies and is buried in Samaria with the kings of Israel; Jeroboam II sits on his throne. The dynasty continues, but the text is about to look back at the extraordinary deathbed scene with Elisha before moving to Jeroboam II's long, prosperous reign.</p>",
    "14": "<p>Elisha falls ill with the illness from which he will die — in contrast to Elijah's translation without death (2:11), Elisha dies of sickness. Joash king of Israel comes down to him and weeps over his face, crying <em>ʾāḇî ʾāḇî rekeḇ yiśrāʾēl ûpārāšāyw</em> — 'my father, my father, the chariots of Israel and its horsemen.' This is verbatim Elisha's cry for Elijah in 2:12; Joash uses the same words that Elisha used, applying the title of prophetic intercessor now to Elisha himself. The prophet was Israel's real military defense — more than chariots.</p>",
    "15": "<p>Elisha instructs Joash to take a bow and arrows; the king takes them. The instruction moves from mourning to symbolic action — the deathbed becomes a prophetic stage.</p>",
    "16": "<p>Elisha instructs Joash to put his hand on the bow; Elisha then lays his own hands on the king's hands — the prophet's hands covering the king's hands on the bow is a transfer of prophetic authority to royal military action, a laying-on-of-hands impartation for the coming campaign.</p>",
    "17": "<p><em>ḥēṣ-tešûʿāh laYHWH wəḥēṣ-tešûʿāh bə ʾărām</em> — 'arrow of YHWH's salvation (<em>tešûʿāh</em>) and arrow of salvation against Aram.' <em>tešûʿāh</em> derives from <em>yāšaʿ</em>, the same root as Yeshua/Joshua — salvation-vocabulary infuses the military prophecy; Elisha declares total victory: Joash will strike Aram at Aphek until he has finished them.</p>",
    "18": "<p>Elisha tells Joash to strike the arrows on the ground; the king strikes three times and stops. Elisha is angry: <em>ləhakkôṯ ḥāmêš ʾô-šēš pəʿāmîm</em> — 'you should have struck five or six times, then you would have struck Aram until you finished it; now you will strike Aram only three times.' The king's half-committed response limits the scope of YHWH's victory; incomplete faith produces incomplete deliverance.</p>",
    "19": "<p>The three limited strikes translate into three limited military victories over Aram — the prophet's word binds the event; the king's action in the prophetic drama predetermined the outcome. The lesson is not that YHWH's power is limited but that the human receptacle limits what YHWH will pour into it.</p>",
    "20": "<p>Elisha dies and is buried. The notice is stark: wayyāmāṯ ʾĕlîšāʿ wayyiqbəruhû — 'and Elisha died and they buried him.' The contrast with Elijah is total: no chariot, no fire, no translation — just death and burial. Yet the death leads immediately to the postmortem miracle of v21.</p>",
    "21": "<p><em>wayyəhî hêm qōḇərîm ʾîš wəhinnēh rāʾû ʾeṯ-haggəḏûḏ wayyašlîḵû ʾeṯ-hāʾîš bəqeḇer ʾĕlîšāʿ wayyēleḵ wayyiggaʿ hāʾîš bəʿaṣmôṯ ʾĕlîšāʿ wayyəḥî wayyāqom ʿal-ragəlāyw</em> — the syntax tumbles with the urgency of the event: they were burying a man, saw raiders, threw the body into Elisha's tomb; the man touched Elisha's bones, <em>wayyəḥî wayyāqom</em> — 'he lived and he stood up on his feet.' The two verbs <em>ḥāyāh</em> (live) and <em>qûm</em> (rise) are resurrection vocabulary; the dead bones of YHWH's prophet still carry his prophetic charge. This is the last Elisha story in Kings.</p>",
    "22": "<p>Hazael king of Aram oppressed Israel all the days of Jehoahaz — a retrospective summary that frames the entire Jehoahaz-to-Jehoash period under Aramean military pressure. The oppression is the context against which YHWH's compassion and the Elisha prophecies operate.</p>",
    "23": "<p><em>wayyəḥunnêm wayyeraḥămêm wayyipen ʾălêhem lǝmaʿan bərîṯô ʾeṯ-ʾaḇrāhām yiṣḥāq wəyaʿăqōḇ</em> — 'YHWH was gracious to them, had compassion on them, and turned to them for the sake of his covenant with Abraham, Isaac, and Jacob.' Three divine verbs: <em>ḥānan</em> (grace), <em>riḥam</em> (compassion/mercy), <em>pānāh</em> (turn/face). YHWH's preservation of Israel is explicitly covenantal — not because Israel deserves it but because YHWH bound himself to Abraham; the Abrahamic covenant underwrites discipline-era Israel's survival.</p>",
    "24": "<p>Hazael king of Aram dies; Ben-hadad his son reigns in his place. The death of Israel's greatest oppressor opens the possibility for the three Elisha-prophesied victories Jehoash will now achieve against the less powerful Ben-hadad III.</p>",
    "25": "<p>Jehoash defeats Ben-hadad three times — exactly the three times prophesied by Elisha's arrow-striking ritual (v18-19). <em>wayyāšeḇ ʾeṯ-ʿārê yiśrāʾēl</em> — 'he restored the cities of Israel,' specifically the cities that Hazael had taken from Jehoahaz. Prophetic word becomes historical event precisely as the prophetic act signified; the limitation was the king's three strikes, not YHWH's capacity.</p>"
  },
  "14": {
    "1": "<p>Amaziah son of Joash begins to reign as king of Judah in the second year of Jehoash son of Jehoahaz of Israel. The synchronism links the Judahite Joash's son to the Israelite Jehoash's second year — a dense chronological web.</p>",
    "2": "<p>Amaziah is twenty-five at accession and reigns twenty-nine years. His mother Jehoaddan is from Jerusalem — a purely Judahite lineage, unlike some queens with foreign connections. The maternal data grounds the king in the Jerusalem community.</p>",
    "3": "<p><em>wayyaʿaś hayyāšār bəʿênê YHWH ʾaḵ lōʾ kəḏāwiḏ ʾāḇîw kəkōl ʾăšer-ʿāśāh Yôʾāš ʾāḇîw ʿāśāh</em> — 'he did right in YHWH's eyes, but not like David his father; according to all that Joash his father had done, he did.' The double qualification: he was better than some but the Davidic standard is still the ceiling he does not reach. His father Joash is the reference-point for his practice, not the ideal David.</p>",
    "4": "<p>The bāmôt formula again: high places not removed; the people still sacrifice and burn incense at the high places. Amaziah's otherwise-positive reign is limited by the decentralized cult that only Josiah will finally address.</p>",
    "5": "<p>Once Amaziah's kingdom was firmly in hand (<em>kahăzaqāh hamamlākāh bəyāḏô</em>), he struck down the servants who had killed his father the king. Political consolidation precedes the act of justice — the sequence is deliberate; Amaziah waits until his position is secure before acting against the assassins.</p>",
    "6": "<p><em>wəʾeṯ-bənê hammaккîm lōʾ hēmîṯ kikāṯûḇ bəsēper ṯôraṯ-môšeh ʾăšer-ṣiwwāh YHWH lēʾmōr lōʾ-yûmtû ʾāḇôṯ ʿal-bānîm ûḇānîm lōʾ-yûmtû ʿal-ʾāḇôṯ kî ʾim-ʾîš bəḥeṭʾô yûmāṯ</em> — 'but the sons of the killers he did not put to death, as written in the Book of the Law of Moses, which YHWH commanded: fathers shall not be put to death for sons, nor sons for fathers; each for his own sin shall he be put to death' (Deut 24:16). This is one of the most explicit Deuteronomic citations in Kings, naming <em>sēper ṯôraṯ-môšeh</em> as the canonical authority. Amaziah applies individual-guilt doctrine against collective-family punishment — a legal principle that resists the ancient Near Eastern norm of clan accountability.</p>",
    "7": "<p>Amaziah defeats ten thousand Edomites in the Valley of Salt (<em>gê-hammelaḥ</em>) and takes Sela (<em>haSSəlaʿ</em> = the rock/cliff), renaming it Joktheel (<em>yoqṯəʾēl</em>). The Valley of Salt links to David's victories in the same locale (2 Sam 8:13); Amaziah's Edom campaign is a minor Davidic echo, though without the significance of the original.</p>",
    "8": "<p>Amaziah sends envoys to Jehoash of Israel: <em>lēḵāh niṯrāʾeh pānîm</em> — 'come, let us look each other in the face,' i.e., meet in battle. The challenge is voluntary military aggression after the Edomite victory — success leading to overreach, a pattern the thistle-cedar parable in v9 directly names.</p>",
    "9": "<p>Jehoash sends back the thistle-cedar parable: a thistle in Lebanon sent to a cedar of Lebanon saying 'give your daughter to my son as wife'; then a wild beast passed by and trampled the thistle. The parable maps as: Amaziah = thistle, Jehoash = cedar; the wild beast = military reality that will crush a small king who overestimates himself. The imagery is from the genre of royal beast-fable; Jehoash deploys it as a dismissal and a warning.</p>",
    "10": "<p><em>hiḵêṯā ʾeṯ ʾĕḏôm ûnsāʾăḵā libbεḵā</em> — 'you have defeated Edom and your heart has lifted you up.' <em>nāśāʾ lēḇāḇ</em> = pride/arrogance, the standard Hebrew idiom for hubris; military success has inflated Amaziah's self-assessment. Jehoash's advice: stay home and glory in your victory — why court disaster?</p>",
    "11": "<p>Amaziah does not listen (<em>lōʾ šāmaʿ</em>). The refusal to heed prophetic-parabolic warning is the pivot of the narrative; what follows is judgment on the refusal. Jehoash and Amaziah face each other at Beth-shemesh in Judah — the battle is in Judahite territory, an invasion of the south.</p>",
    "12": "<p>Judah is defeated before Israel; every man flees to his home. <em>wayyinnāgep Yəhûḏāh</em> — Judah is struck/routed. The defeat is total and humiliating; a Judahite king whose overconfidence led him to invade Israel is beaten on his own soil.</p>",
    "13": "<p>Jehoash captures Amaziah at Beth-shemesh and brings him to Jerusalem. He then tears down the Jerusalem wall from the Gate of Ephraim to the Corner Gate — four hundred cubits of the city wall — breaching the city's defenses. The physical breach enacts the humiliation; Amaziah's overconfidence ends in his capital's wall destroyed.</p>",
    "14": "<p>Jehoash takes all the gold and silver and all the vessels found in YHWH's house and the palace, plus hostages, and returns to Samaria. The looting parallels Shishak's plunder under Rehoboam (1 Kgs 14:25-26) and Hazael's extortion under Joash (12:18) — the temple and palace assets circulate between kingdoms as military spoils.</p>",
    "15": "<p>The rest of Jehoash's acts — his might (<em>gəḇûrāṯô</em>) and his war with Amaziah — are in the chronicles of the kings of Israel. This is the second archival notice for Jehoash (the first in 13:12), forming brackets around the Elisha deathbed and the Amaziah battle sections.</p>",
    "16": "<p>Jehoash dies and is buried in Samaria with the kings of Israel; Jeroboam II his son reigns in his place. The short notice launches the most economically and militarily successful reign in Israel's history.</p>",
    "17": "<p>Amaziah outlives Jehoash by fifteen years — he reigns twenty-nine years total, the last fifteen as a defeated, partially humiliated king. The text notes his survival after Jehoash's death without suggesting rehabilitation; the defeat defined the rest of his reign.</p>",
    "18": "<p>The rest of Amaziah's acts are in the Book of the Chronicles of the Kings of Judah — the archival reference for Judah's kings, parallel to Israel's chronicle.</p>",
    "19": "<p>A conspiracy against Amaziah arises in Jerusalem; he flees to Lachish (<em>lāḵîš</em>), the fortified Judahite city in the Shephelah. They send after him to Lachish and kill him there. The king who began by lawfully punishing his father's assassins ends by being assassinated himself — an ironic structural closure on the Joash-Amaziah regnal pair.</p>",
    "20": "<p>They bring his body on horses and bury him with his fathers in Jerusalem in the City of David. The burial honors the Davidic dynastic convention; despite assassination, he receives royal burial.</p>",
    "21": "<p>All the people of Judah (<em>ʿam Yəhûḏāh</em>) take Azariah (Uzziah), sixteen years old, and make him king in place of his father Amaziah. The people's role in the accession is unusual — normally succession is automatic; the people's active choice suggests a period of instability after the assassination.</p>",
    "22": "<p>Azariah built Elath (<em>ʾêlaṯ</em>) and restored it to Judah — probably the Red Sea port (Ezion-geber area) that gives access to trade routes; this brief note of building and restoration is one of the more positive administrative achievements attributed to any Judahite king in this period.</p>",
    "23": "<p>Jeroboam II son of Jehoash begins to reign over Israel in Samaria in the fifteenth year of Amaziah of Judah. His forty-one year reign (the longest of any northern king) makes him the most durable ruler of the Jehu dynasty and of the northern kingdom altogether.</p>",
    "24": "<p><em>wayyaʿaś hārāʿ bəʿênê YHWH lōʾ-sār mikkol-ḥaṭṭôʾṯ Yārābəʿām</em> — the standard northern-kingdom indictment despite Jeroboam II's extraordinary political and military success. The Deuteronomic historian evaluates by covenant faithfulness, not by political achievement; the most successful northern king still receives the lowest theological grade.</p>",
    "25": "<p><em>hûʾ hēšîḇ ʾeṯ-gəḇûl yiśrāʾēl mimmābôʾ ḥămaṯ ʿaḏ-yām hāʿărāḇāh kidbar YHWH ʾĕlōhê yiśrāʾēl ʾăšer dibber bəyaḏ-ʿaḇḏô Yônāh ḇen-ʾĂmiṯṯay hannāḇîʾ</em> — 'he restored the border of Israel from Lebo-hamath to the Sea of the Arabah, according to the word of YHWH the God of Israel, which he spoke by his servant Jonah son of Amittai, the prophet.' This is the only mention of Jonah ben Amittai in Kings; he is identified as a prophet who proclaimed Israel's territorial restoration — a very different commission from the Nineveh mission of the book named for him. <em>ʿeḇeḏ YHWH</em> (servant of YHWH) here applied to Jonah is the same designation as the Isaianic Servant Songs; Jonah is simultaneously a historical prophet and an ironic figure whose own book records his reluctance to deliver YHWH's word.</p>",
    "26": "<p><em>ʾêyn ʿōṣēr wəʾêyn ʿāzēr lə yiśrāʾēl</em> — 'there was no one restraining and no one helping for Israel'; the nation was in its most desperate condition. YHWH saw Israel's exceedingly bitter affliction (<em>mar məʾōḏ</em>) and that there was none — literally, no deliverer. The divine seeing and responding to communal desperate suffering underlies the restoration through Jeroboam II.</p>",
    "27": "<p><em>wəlōʾ-ḏibber YHWH lǝmāḥôṯ ʾeṯ-šēm yiśrāʾēl mittaḥaṯ haššāmayim</em> — 'and YHWH had not spoken to blot out the name of Israel from under heaven.' The Deuteronomic covenant includes total covenant dissolution as the ultimate sanction; YHWH's restraint from enacting this — despite continued Jeroboam-pattern sins — is attributed to his compassion (v26). YHWH saves Israel through Jeroboam II not because of the king's righteousness but because of his own prior commitment not to blot out the name.</p>",
    "28": "<p>The rest of Jeroboam II's acts — his might (<em>gəḇûrāṯô</em>), his wars, his restoration of Damascus and Hamath to Judah (reading with LXX) — are in the chronicles of the kings of Israel. The extraordinary scope of his campaigns is noted and then referenced to the archive; the historian is more interested in covenant evaluation than in military geography.</p>",
    "29": "<p>Jeroboam II dies and is buried in Samaria with the kings of Israel; his son Zechariah reigns in his place. The single succession line that ends four generations later in Zechariah's assassination (2 Kgs 15:10) closes the Jehu dynasty — the longest-ruling northern dynasty ends with the dynasty's predicted limit (2 Kgs 10:30: four generations on the throne).</p>"
  }
}

